import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Validate input length
        if (name.length() > 10) {
            System.out.println("Name is too long. Please enter a name with at most 10 characters.");
            return;
        }

        char[] buffer = new char[10];

        // Copy characters from name to buffer with bounds checking
        for (int i = 0; i < name.length() && i < buffer.length; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Your name is: " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
